arguments.query:
WITH MergedOrders AS (
    SELECT MIN(id) AS id, external_reference_number, SUM(amount) AS total_amount
    FROM orders
    GROUP BY external_reference_number
)
DELETE FROM orders
WHERE id NOT IN (SELECT id FROM MergedOrders);

INSERT INTO orders (external_reference_number, amount)
SELECT external_reference_number, total_amount
FROM MergedOrders;
